// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title TrustLend
 * @notice Peer-to-peer lending protocol on Polygon.
 *         Loans are denominated in native POL.
 *         Trust scores and KYC remain off-chain (Supabase).
 * @dev Deploy on Polygon Amoy testnet (chainId 80002).
 */
contract TrustLend {
    /* ── Types ── */

    enum LoanStatus { Pending, Active, Repaid, Defaulted }

    struct Loan {
        uint256 id;
        address borrower;
        address lender;
        uint256 amount;       // in wei (POL)
        uint256 collateralHeld; // in wei (POL)
        uint256 createdAt;
        uint256 dueAt;        // 30-day term
        LoanStatus status;
        bytes32 supabaseRef;  // off-chain loan row id (bytes32 of UUID)
    }

    struct Vouch {
        uint256 id;
        address voucher;
        address borrower;
        uint256 stakeAmount;  // in wei
        bool    active;
    }

    /* ── State ── */

    address public owner;
    uint256 public loanCounter;
    uint256 public vouchCounter;

    // 30-day loan term
    uint256 public constant LOAN_TERM = 30 days;

    // Minimum stake per vouch (0.001 POL)
    uint256 public constant MIN_VOUCH_STAKE = 0.001 ether;

    mapping(uint256 => Loan)  public loans;
    mapping(uint256 => Vouch) public vouches;

    // borrower => active loan id (0 = none)
    mapping(address => uint256) public activeLoanOf;

    // borrower => vouch ids
    mapping(address => uint256[]) public vouchesFor;

    /* ── Events ── */

    event LoanRequested(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 amount,
        bytes32 supabaseRef
    );

    event LoanFunded(
        uint256 indexed loanId,
        address indexed lender,
        uint256 amount
    );

    event LoanRepaid(
        uint256 indexed loanId,
        address indexed borrower,
        address indexed lender,
        uint256 amount
    );

    event LoanDefaulted(
        uint256 indexed loanId,
        address indexed borrower
    );

    event VouchStaked(
        uint256 indexed vouchId,
        address indexed voucher,
        address indexed borrower,
        uint256 amount
    );

    event VouchReleased(
        uint256 indexed vouchId,
        address indexed voucher,
        uint256 amount
    );

    /* ── Modifiers ── */

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    /* ── Constructor ── */

    constructor() {
        owner = msg.sender;
    }

    /* ── Borrower Functions ── */

    /**
     * @notice Borrower requests a loan. Amount must match msg.value = 0
     *         (funds come FROM lender, not borrower).
     * @param amount      Loan amount in wei (POL)
     * @param supabaseRef bytes32 encoding of the Supabase loan UUID
     */
    function requestLoan(uint256 amount, bytes32 supabaseRef) external {
        require(amount > 0, "Amount must be > 0");
        require(activeLoanOf[msg.sender] == 0, "Existing active loan");

        loanCounter++;
        uint256 loanId = loanCounter;

        loans[loanId] = Loan({
            id:             loanId,
            borrower:       msg.sender,
            lender:         address(0),
            amount:         amount,
            collateralHeld: 0,
            createdAt:      block.timestamp,
            dueAt:          block.timestamp + LOAN_TERM,
            status:         LoanStatus.Pending,
            supabaseRef:    supabaseRef
        });

        activeLoanOf[msg.sender] = loanId;

        emit LoanRequested(loanId, msg.sender, amount, supabaseRef);
    }

    /**
     * @notice Borrower requests a loan with 110% collateral (Asset-Backed).
     *         msg.value must be the collateral amount.
     * @param amount      Loan amount in wei (POL)
     * @param supabaseRef bytes32 encoding of the Supabase loan UUID
     */
    function requestLoanWithCollateral(uint256 amount, bytes32 supabaseRef) external payable {
        require(amount > 0, "Amount must be > 0");
        require(msg.value >= (amount * 110) / 100, "Insufficient collateral (need 110%)");
        require(activeLoanOf[msg.sender] == 0, "Existing active loan");

        loanCounter++;
        uint256 loanId = loanCounter;

        loans[loanId] = Loan({
            id:             loanId,
            borrower:       msg.sender,
            lender:         address(0),
            amount:         amount,
            collateralHeld: msg.value,
            createdAt:      block.timestamp,
            dueAt:          block.timestamp + LOAN_TERM,
            status:         LoanStatus.Pending,
            supabaseRef:    supabaseRef
        });

        activeLoanOf[msg.sender] = loanId;

        emit LoanRequested(loanId, msg.sender, amount, supabaseRef);
    }

    /**
     * @notice Lender funds a pending loan.
     *         msg.value must equal the loan amount exactly.
     * @param loanId The loan to fund
     */
    function fundLoan(uint256 loanId) external payable {
        Loan storage loan = loans[loanId];
        require(loan.status == LoanStatus.Pending, "Loan not pending");
        require(msg.value == loan.amount, "Wrong POL amount");
        require(msg.sender != loan.borrower, "Cannot self-fund");

        loan.lender = msg.sender;
        loan.status = LoanStatus.Active;

        // Transfer funds to borrower
        (bool ok, ) = loan.borrower.call{value: msg.value}("");
        require(ok, "Transfer to borrower failed");

        emit LoanFunded(loanId, msg.sender, msg.value);
    }

    /**
     * @notice Borrower repays an active loan in full (principal only, 0% APR).
     *         msg.value must equal the loan amount exactly.
     * @param loanId The loan to repay
     */
    function repayLoan(uint256 loanId) external payable {
        Loan storage loan = loans[loanId];
        require(loan.status == LoanStatus.Active, "Loan not active");
        require(msg.sender == loan.borrower, "Not borrower");
        require(msg.value == loan.amount, "Wrong repayment amount");

        loan.status = LoanStatus.Repaid;
        activeLoanOf[msg.sender] = 0;

        // Release voucher stakes
        _releaseVouches(loan.borrower);

        // Release collateral back to borrower
        if (loan.collateralHeld > 0) {
            uint256 col = loan.collateralHeld;
            loan.collateralHeld = 0;
            (bool okCol, ) = msg.sender.call{value: col}("");
            require(okCol, "Collateral return failed");
        }

        // Transfer repayment to lender
        (bool ok, ) = loan.lender.call{value: msg.value}("");
        require(ok, "Transfer to lender failed");

        emit LoanRepaid(loanId, loan.borrower, loan.lender, msg.value);
    }

    /* ── Vouch Functions ── */

    /**
     * @notice Stake POL as a vouch for a borrower.
     *         Stake is locked until borrower repays or defaults.
     * @param borrower Address of the borrower to vouch for
     */
    function stakeVouch(address borrower) external payable {
        require(msg.value >= MIN_VOUCH_STAKE, "Stake too low");
        require(msg.sender != borrower, "Cannot self-vouch");

        vouchCounter++;
        uint256 vouchId = vouchCounter;

        vouches[vouchId] = Vouch({
            id:          vouchId,
            voucher:     msg.sender,
            borrower:    borrower,
            stakeAmount: msg.value,
            active:      true
        });

        vouchesFor[borrower].push(vouchId);

        emit VouchStaked(vouchId, msg.sender, borrower, msg.value);
    }

    /* ── Internal ── */

    function _releaseVouches(address borrower) internal {
        uint256[] storage ids = vouchesFor[borrower];
        for (uint256 i = 0; i < ids.length; i++) {
            Vouch storage v = vouches[ids[i]];
            if (v.active) {
                v.active = false;
                (bool ok, ) = v.voucher.call{value: v.stakeAmount}("");
                if (ok) emit VouchReleased(v.id, v.voucher, v.stakeAmount);
            }
        }
        delete vouchesFor[borrower];
    }

    /* ── Owner / Admin ── */

    /**
     * @notice Mark overdue loan as defaulted (owner only).
     *         Vouch stakes are slashed (kept in contract).
     */
    function markDefaulted(uint256 loanId) external onlyOwner {
        Loan storage loan = loans[loanId];
        require(loan.status == LoanStatus.Active, "Not active");
        require(block.timestamp > loan.dueAt, "Not overdue yet");

        loan.status = LoanStatus.Defaulted;
        activeLoanOf[loan.borrower] = 0;
        // Vouch stakes remain in contract as penalty

        emit LoanDefaulted(loanId, loan.borrower);
    }

    /// @notice Emergency withdraw (owner only)
    function withdraw() external onlyOwner {
        (bool ok, ) = owner.call{value: address(this).balance}("");
        require(ok, "Withdraw failed");
    }

    /* ── View Helpers ── */

    function getLoan(uint256 loanId) external view returns (Loan memory) {
        return loans[loanId];
    }

    function getVouchesFor(address borrower) external view returns (uint256[] memory) {
        return vouchesFor[borrower];
    }
}

